import{_ as a,o as s,c as i,a as o}from"./chunks/framework.BHSVNLI7.js";const u=JSON.parse('{"title":"编译你的第一个 ARM64 内核","description":"","frontmatter":{"title":"编译你的第一个 ARM64 内核","prerequisites":["kernel-mini-config"],"next":["busybox-rootfs"],"difficulty":"beginner","tags":["kernel-build","arm64","kbuild","make"],"architectures":["arm64"],"kernel_version":"6.19"},"headers":[],"relativePath":"tutorials/foundations/kernel-build.md","filePath":"tutorials/foundations/kernel-build.md","lastUpdated":null}'),n={name:"tutorials/foundations/kernel-build.md"};function t(d,e,l,r,c,p){return s(),i("div",null,[...e[0]||(e[0]=[o(`<h2 id="做什么" tabindex="-1">做什么 <a class="header-anchor" href="#做什么" aria-label="Permalink to &quot;做什么&quot;">​</a></h2><p>这篇我们就干一件事——把上一份精心配置的 mini config 编译成一颗能跑的 ARM64 内核。编译本身只是一行 make 命令，但内核构建系统的输出信息非常丰富，值得花时间理解一下每行输出到底在说什么。完成之后我们会得到一个 <code>Image</code> 文件——这就是 ARM64 的内核启动镜像，后续 QEMU 会加载它来启动系统。</p><h2 id="要了解什么" tabindex="-1">要了解什么 <a class="header-anchor" href="#要了解什么" aria-label="Permalink to &quot;要了解什么&quot;">​</a></h2><h3 id="发起编译" tabindex="-1">发起编译 <a class="header-anchor" href="#发起编译" aria-label="Permalink to &quot;发起编译&quot;">​</a></h3><p>确认你已经完成了上一篇的三步配置流程，<code>out/build_latest_arm64/.config</code> 存在且内容正确。然后在 <code>third_party/linux/</code> 目录下执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=aarch64-linux-gnu-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     O=../../out/build_latest_arm64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nproc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>-j$(nproc)</code> 会自动使用所有可用的 CPU 核心进行并行编译。我们的 14 线程机器上，一次 mini config 编译大约 3-5 分钟；如果用 <code>defconfig</code> 的 952 项配置，时间会翻倍甚至更多。</p><p>编译过程中你会看到大量输出在终端里飞速滚动，每一行前面都有一个短标签。如果你觉得这些标签像天书，完全没关系——因为接下来我们就来拆解它们。</p><h3 id="编译输出标签速查" tabindex="-1">编译输出标签速查 <a class="header-anchor" href="#编译输出标签速查" aria-label="Permalink to &quot;编译输出标签速查&quot;">​</a></h3><p>内核构建系统为每种操作定义了一个缩写标签，由 <code>scripts/Makefile.*</code> 里的 <code>quiet_cmd_*</code> 变量控制。默认模式下（不加 <code>V=</code> 参数），make 只显示这些缩写而不是完整的命令行，目的是让输出更紧凑可读。</p><p>首先是最核心的编译类标签。<strong>CC</strong> 是你见到最多的，代表 C 编译器把 <code>.c</code> 源文件编译成 <code>.o</code> 目标文件；如果后面跟着 <code>[M]</code>，说明这个文件被编译为可加载模块（<code>.ko</code>）而不是内建到内核主体中。<strong>AS</strong> 是汇编器，处理 <code>.S</code> 汇编源文件——ARM64 的启动代码、中断处理、上下文切换等关键路径很多都是汇编写的。<strong>LD</strong> 是链接器，把多个 <code>.o</code> 文件链接成一个更大的目标，同样 <code>[M]</code> 表示链接的是模块。<strong>AR</strong> 是归档器，把一批 <code>.o</code> 文件打包成 <code>.a</code> 静态库——内核源码里每个子目录最终都会产出一个 <code>built-in.a</code>，里面包含了该目录下所有需要内建到内核的目标文件。</p><p>然后是宿主机工具类。<strong>HOSTCC</strong> 和 <strong>HOSTLD</strong> 分别编译和链接运行在宿主机（我们的 x86_64 WSL2）上的辅助工具。这些工具不是给目标板用的，而是内核构建过程本身需要的一些小工具，比如生成内核符号表、处理设备树等。你可能还会看到 <strong>HOSTCXX</strong>，那是编译 C++ 宿主机工具（比如 KConfig 的 Qt 图形界面配置工具）。</p><p>生成和检查类的标签也经常出现。<strong>GEN</strong> 表示生成各种中间文件，比如 <code>asm-offsets</code>（汇编和 C 之间的常量桥接）、<code>autoconf.h</code>（把 <code>.config</code> 转成 C 头文件）。<strong>CHK</strong> 和 <strong>UPD</strong> 是一对搭档——<code>CHK</code> 检查某个文件的内容是否需要重新生成，如果检查发现内容变了，就跟着一行 <code>UPD</code> 表示实际更新了文件。</p><p>设备树相关的标签在 ARM 平台上很常见。<strong>DTC</strong> 是 Device Tree Compiler，把 <code>.dts</code> 源文件编译成 <code>.dtb</code> 二进制 blob。设备树是 ARM 平台描述硬件拓扑的标准方式，QEMU virt 机器虽然会自动生成设备树，但内核内部也有一些编译时嵌入的设备树 blob。</p><p>模块相关的标签出现在编译的末尾阶段。<strong>MODPOST</strong> 是模块后处理，它会生成 <code>Module.symvers</code> 文件（记录所有导出符号的版本信息）并检查模块的符号依赖。<strong>SIGN</strong> 给模块签名（如果开启了 <code>CONFIG_MODULE_SIG</code>），<strong>DEPMOD</strong> 生成模块依赖关系文件 <code>modules.dep</code>。</p><p>如果你想看每个标签背后的完整命令行，只需要在 make 命令后面加 <code>V=1</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CROSS_COMPILE=aarch64-linux-gnu-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     O=../../out/build_latest_arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> V=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nproc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样每一步操作都会打印完整的 gcc/ld 命令，包括所有编译选项、头文件搜索路径、宏定义等。调试编译问题的时候 <code>V=1</code> 是必备的。</p><h3 id="验证编译结果" tabindex="-1">验证编译结果 <a class="header-anchor" href="#验证编译结果" aria-label="Permalink to &quot;验证编译结果&quot;">​</a></h3><p>编译成功后，最后一行输出应该类似：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LD      arch/arm64/boot/Image</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>ARM64 的内核启动镜像叫 <code>Image</code>（注意没有压缩），位于编译输出目录的 <code>arch/arm64/boot/</code> 下。我们用 <code>file</code> 命令确认它的格式：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/build_latest_arm64/arch/arm64/boot/Image</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux kernel ARM64 boot executable Image, little-endian, 4K pages</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>看到 <code>Linux kernel ARM64 boot executable Image</code> 就对了。ARM32 平台的镜像名字和格式不一样，那里叫 <code>zImage</code>（自解压压缩镜像），但原理一样——QEMU 加载这个文件然后跳进去执行。</p><p>除了 <code>Image</code> 之外，编译输出目录里还有一个重要的文件 <code>vmlinux</code>。它是未压缩的 ELF 格式内核，包含完整的符号表和调试信息，后面 GDB 调试的时候需要用到它。<code>Image</code> 是从 <code>vmlinux</code> 经过 <code>objcopy</code> 剥离了 ELF 头和调试信息之后生成的纯二进制镜像，体积更小，适合 QEMU 加载。</p><h3 id="输出目录结构" tabindex="-1">输出目录结构 <a class="header-anchor" href="#输出目录结构" aria-label="Permalink to &quot;输出目录结构&quot;">​</a></h3><p>我们使用 <code>O=</code> 参数把所有编译产物放到 <code>out/build_latest_arm64/</code> 目录，而不是在源码树里到处散落文件。这个目录的结构基本是源码树结构的镜像——源码树里 <code>kernel/sched/</code> 下的源文件编译后的 <code>.o</code> 产物在 <code>out/build_latest_arm64/kernel/sched/</code> 下，源码树里 <code>arch/arm64/boot/</code> 下的启动镜像在 <code>out/build_latest_arm64/arch/arm64/boot/</code> 下。这种分离的好处是源码树保持干净，切换不同架构的编译输出也不会互相污染。就像咱们自己写C/C++工程的时候，也都会用类似CMake的构建工具指定合适的构建目录处理。对不对？</p><h2 id="动手试试" tabindex="-1">动手试试 <a class="header-anchor" href="#动手试试" aria-label="Permalink to &quot;动手试试&quot;">​</a></h2><ol><li>确认上一节的配置流程已完成，<code>out/build_latest_arm64/.config</code> 存在</li><li>执行编译命令，观察终端输出中的各种标签</li><li>编译完成后用 <code>file</code> 命令验证 <code>Image</code> 文件的格式</li><li>用 <code>ls -lh out/build_latest_arm64/arch/arm64/boot/Image out/build_latest_arm64/vmlinux</code> 对比两者的大小，理解为什么 QEMU 用 <code>Image</code> 而 GDB 用 <code>vmlinux</code></li><li>试试 <code>V=1</code> 编译（可以只编一个文件：<code>make O=... arch/arm64/kernel/setup.o V=1</code>），看看完整命令行长什么样</li></ol><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://docs.kernel.org/admin-guide/README.html" target="_blank" rel="noreferrer">Linux 内核构建说明</a> — kernel.org 官方的编译指南</li><li><a href="https://www.kernel.org/doc/html/latest/kbuild/kbuild.html" target="_blank" rel="noreferrer">Kbuild 文档</a> — 构建系统的详细文档</li></ul>`,31)])])}const k=a(n,[["render",t]]);export{u as __pageData,k as default};
